class Node:
    def __init__(self, data):
        self.data = data
        self.next = None

def sorted_circular_linked_list_insert(head, data):
    new_node = Node(data)

    if head is None:
        new_node.next = new_node
        return new_node

    current = head
    if data <= head.data:
        while current.next != head:
            current = current.next
        current.next = new_node
        new_node.next = head
        return new_node

    else:
        while current.next != head and current.next.data < data:
            current = current.next

        new_node.next = current.next
        current.next = new_node
        return head

if __name__ == '__main__':
    # Örnek Kullanım
    head = None

    head = sorted_circular_linked_list_insert(head, 12)
    head = sorted_circular_linked_list_insert(head, 56)
    head = sorted_circular_linked_list_insert(head, 2)
    head = sorted_circular_linked_list_insert(head, 1)
    head = sorted_circular_linked_list_insert(head, 90)

    current = head
    if head:
      print("Dairesel Bağlı Liste:")
      while True:
          print(current.data, end=" ")
          current = current.next
          if current == head:
              break
      print()
